int is_perm(int perm[], int laenge) {

  int *anzahl;
  int wert = 1;
  int i;

  if (perm == NULL)
    return -1;

  /* Test auf wohldefiniert Eingabe , siehe unten */
  for (i = 0; i < laenge; i++) {
    if (perm[i] < 1 || perm[i] > laenge)
      return 0;
    /* Fehler waere auch OK */
  }

  if ((anzahl = malloc(laenge * sizeof(int))) == NULL)
    return -3;

  for (i = 0; i < laenge; i++)
    anzahl[i] = 0;

  for (i = 0; i < laenge; i++)
    ++anzahl[perm[i] - 1];

  for (i = 0; i < laenge; i++)
    wert = wert & (anzahl[i] == 1);

  free(anzahl);
  return wert;
}

